// Parse GPT response and extract enhanced strategy
const response = $input.first().json;
const content = JSON.parse(response.choices[0].message.content);

// Separate images into static and animated
const staticImages = [];
const animatedImages = [];

content.midjourney_prompts.forEach((item, index) => {
  if (item.animate) {
    animatedImages.push({
      index: index,
      prompt: item.prompt,
      motion: item.motion
    });
  } else {
    staticImages.push({
      index: index,
      prompt: item.prompt
    });
  }
});

return {
  json: {
    strategy: content.strategy,
    script: content.script,
    midjourney_prompts: content.midjourney_prompts,
    timing: content.timing,
    music_selection: content.music_selection,
    performance_estimate: content.performance_estimate,
    // Categorized images
    static_images: staticImages,
    animated_images: animatedImages,
    // Store original product data
    product_name: $('Extract Product Data').first().json.product_name
  }
};

// Collect all downloaded images and preserve metadata
const allInputs = $input.all();
const strategy = $('Parse Enhanced Strategy').first().json;

const images = allInputs.map((item, index) => {
  const promptData = strategy.midjourney_prompts[index];

  return {
    binary: item.binary,
    index: index,
    should_animate: promptData.animate,
    motion_type: promptData.motion || 'none',
    timing: strategy.timing[index]
  };
});

return images.map(img => ({ json: img, binary: img.binary }));

// PLACEHOLDER for Runway Gen-3 animation
// When Runway Gen-3 API is available, this will:
// 1. Take images where should_animate = true
// 2. Send to Runway Gen-3 with motion prompts
// 3. Download animated videos
// 4. Return mix of static images + animated videos

// FOR NOW: Just pass through all static images
const allImages = $input.all();

return allImages.map(item => ({
  json: {
    ...item.json,
    animated: false,
    note: 'Runway Gen-3 animation will be added here when API is available'
  },
  binary: item.binary
}));

