// Select music from Epidemic Sound library based on mood
// TODO: Upload Epidemic Sound tracks to n8n and update paths

const strategy = $('Parse Enhanced Strategy').first().json.strategy;
const musicSelection = $('Parse Enhanced Strategy').first().json.music_selection;

// Epidemic Sound library organized by mood
const musicLibrary = {
  energetic: [
    '/data/epidemic-sound/energetic/upbeat-pop-1.mp3',
    '/data/epidemic-sound/energetic/electronic-beat-1.mp3',
    '/data/epidemic-sound/energetic/indie-rock-1.mp3'
  ],
  calm: [
    '/data/epidemic-sound/calm/acoustic-chill-1.mp3',
    '/data/epidemic-sound/calm/ambient-soft-1.mp3'
  ],
  upbeat: [
    '/data/epidemic-sound/upbeat/happy-pop-1.mp3',
    '/data/epidemic-sound/upbeat/funky-groove-1.mp3'
  ],
  inspirational: [
    '/data/epidemic-sound/inspirational/emotional-piano-1.mp3',
    '/data/epidemic-sound/inspirational/uplifting-strings-1.mp3'
  ]
};

const mood = musicSelection.mood || strategy.mood || 'energetic';
const tracksForMood = musicLibrary[mood] || musicLibrary.energetic;
const selectedTrack = tracksForMood[Math.floor(Math.random() * tracksForMood.length)];

return {
  json: {
    music_path: selectedTrack,
    music_volume: 0.25, // Background music at 25% (professional mix)
    mood: mood,
    bpm_range: musicSelection.bpm_range,
    genre: musicSelection.genre
  }
};

// Build ADVANCED Shotstack timeline for Standard version
const strategy = $('Parse Enhanced Strategy').first().json;
const images = $input.all().filter(item => item.binary?.data);
const voiceover = $('ElevenLabs Voiceover (Enhanced)').first();
const music = $('Select Epidemic Sound Track').first().json;

// Advanced transition mapping
const transitionMap = {
  'fade': { in: 'fade', out: 'fade' },
  'wipe_left': { in: 'wipeLeft', out: 'wipeRight' },
  'zoom_in': { in: 'zoomIn', out: 'fade' },
  'slide_up': { in: 'slideUp', out: 'slideDown' },
  'smooth': { in: 'fade', out: 'fade' },
  'snappy': { in: 'wipeLeft', out: 'wipeRight' },
  'cinematic': { in: 'zoomIn', out: 'fade' }
};

// Build image clips with ADVANCED effects
let currentTime = 0;
const imageClips = strategy.timing.map((timing, index) => {
  const transition = transitionMap[timing.transition] || transitionMap['fade'];
  const clip = {
    asset: {
      type: 'image',
      src: `data:image/png;base64,${images[index].binary.data.toString('base64')}`
    },
    start: currentTime,
    length: timing.duration,
    fit: 'cover',
    scale: 1.1, // Ken Burns effect (slight zoom)
    transition: transition,
    effect: images[index].json?.should_animate ? 'zoomIn' : 'slideRight',
    opacity: 1
  };

  currentTime += timing.duration;
  return clip;
});

const totalDuration = currentTime;

// Build timeline with MULTIPLE tracks
const timeline = {
  soundtrack: {
    src: music.music_path,
    effect: 'fadeInFadeOut',
    volume: music.music_volume
  },
  tracks: [
    // Track 1: Images
    {
      clips: imageClips
    },
    // Track 2: Voiceover
    {
      clips: [
        {
          asset: {
            type: 'audio',
            src: `data:audio/mpeg;base64,${voiceover.binary.data.toString('base64')}`
          },
          start: 0,
          length: totalDuration,
          volume: 1.0
        }
      ]
    }
  ]
};

// Track 3: Text overlays with ANIMATIONS
const textClips = strategy.timing
  .filter(t => t.text_overlay)
  .map(timing => {
    const startTime = strategy.timing.slice(0, timing.image).reduce((sum, t) => sum + t.duration, 0);

    return {
      asset: {
        type: 'title',
        text: timing.text_overlay,
        style: 'minimal',
        color: '#ffffff',
        size: 'large',
        background: 'rgba(0,0,0,0.6)',
        position: timing.image === 0 ? 'top' : (timing.image === strategy.timing.length - 1 ? 'bottom' : 'center')
      },
      start: startTime,
      length: Math.min(3, timing.duration),
      transition: {
        in: 'slideUp',
        out: 'fade'
      },
      effect: 'zoomIn'
    };
  });

if (textClips.length > 0) {
  timeline.tracks.push({ clips: textClips });
}

return {
  json: {
    timeline: timeline,
    output: {
      format: 'mp4',
      resolution: '1080',
      aspectRatio: '9:16',
      fps: 30,
      quality: 'high',
      repeat: false,
      mute: false
    },
    poster: {
      capture: 1.0
    },
    callback: null
  }
};
